func TestDetectGoModuleConfig(t *testing.T) {
	tests := map[string]struct {
		setup          func(t *testing.T) string
		wantModulePath string
		wantLang       string
	}{
		"success: nearest go.mod is used": {
			setup: func(t *testing.T) string {
				root := t.TempDir()
				writeTextFile(t, filepath.Join(root, "go.mod"), "module example.com/acme/project\n\ngo 1.26\n")
				outDir := filepath.Join(root, "internal", "models")
				if err := os.MkdirAll(outDir, 0o755); err != nil {
					t.Fatalf("creating out dir: %v", err)
				}
				return outDir
			},
			wantModulePath: "example.com/acme/project",
			wantLang:       "go1.26",
		},
		"success: no go.mod returns empty config": {
			setup: func(t *testing.T) string {
				return t.TempDir()
			},
			wantModulePath: "",
			wantLang:       "",

--- end ---
			wantLang:       "",
		},
	}

	for name, tt := range tests {
		t.Run(name, func(t *testing.T) {
			outDir := tt.setup(t)
			gotModulePath, gotLang := detectGoModuleConfig(outDir)
			if gotModulePath != tt.wantModulePath || gotLang != tt.wantLang {
				t.Fatalf("detectGoModuleConfig(%q) = (%q, %q), want (%q, %q)", outDir, gotModulePath, gotLang, tt.wantModulePath, tt.wantLang)
			}
		})
	}
}

func newSimpleSchema(tableNames ...string) *Schema {
	types := make([]Type, 0, len(tableNames))
	for _, tableName := range tableNames {
		typ := Type{
			Name:  snakeToCamel(tableName),
			Table: tableName,
			Fields: []Field{
				{
					Name:            "Id",
					ColumnName:      "id",
					GoType:          "int64",
					SpannerType:     "INT64",
					BaseSpannerType: "INT64",
					NotNull:         true,
					IsPrimaryKey:    true,
				},
			},
		}
		refreshTypeMetadata(&typ)
		types = append(types, typ)
	}
	return &Schema{Types: types}
}

func generateFromSchema(t *testing.T, schema *Schema, opts Options) string {
	t.Helper()

	if opts.OutDir == "" {
		opts.OutDir = filepath.Join(t.TempDir(), "models")
	}
	if opts.PackageName == "" {
		opts.PackageName = "models"
	}

	if err := NewGenerator(opts).Generate(schema); err != nil {
		t.Fatalf("Generate() error = %v", err)
	}

	return opts.OutDir
}

func generateFromDDL(t *testing.T, root, ddl string, opts Options) string {
	t.Helper()

	schemaPath := filepath.Join(root, "schema.sql")
	writeTextFile(t, schemaPath, ddl)

	schema, err := NewDDLFileSource(schemaPath).Load(t.Context())
	if err != nil {
		t.Fatalf("Load() error = %v", err)
	}

	if opts.OutDir == "" {
		opts.OutDir = filepath.Join(root, "models")
	}

	return generateFromSchema(t, schema, opts)
}

func readTextFile(t *testing.T, path string) string {
	t.Helper()

	data, err := os.ReadFile(path)
	if err != nil {
		t.Fatalf("reading %s: %v", path, err)
	}
	return string(data)
}

func writeTextFile(t *testing.T, path, content string) {
	t.Helper()

	if err := os.MkdirAll(filepath.Dir(path), 0o755); err != nil {
		t.Fatalf("creating directory for %s: %v", path, err)
	}
	if err := os.WriteFile(path, []byte(content), 0o644); err != nil {
		t.Fatalf("writing %s: %v", path, err)
	}
}

func listFiles(t *testing.T, dir string) []string {
	t.Helper()

	entries, err := os.ReadDir(dir)
	if err != nil {
		t.Fatalf("reading directory %s: %v", dir, err)
	}

	names := make([]string, 0, len(entries))
	for _, entry := range entries {
		if entry.IsDir() {
			continue
		}
		names = append(names, entry.Name())
	}
	sort.Strings(names)
	return names
}

func filterFiles(items []string, keep func(string) bool) []string {
	out := make([]string, 0, len(items))
	for _, item := range items {
		if keep(item) {
			out = append(out, item)
		}
	}
	return out
}

func newCompileFixtureRoot(t *testing.T) string {
	t.Helper()

	if err := os.MkdirAll("testdata", 0o755); err != nil {
		t.Fatalf("creating testdata directory: %v", err)
	}
	root, err := os.MkdirTemp("testdata", "generated-")
	if err != nil {
		t.Fatalf("creating compile fixture root: %v", err)
	}
	root, err = filepath.Abs(root)
	if err != nil {
		t.Fatalf("resolving compile fixture root: %v", err)
	}
	t.Cleanup(func() {
		_ = os.RemoveAll(root)
	})
	return root
}

func moduleImportPath(t *testing.T, absPath string) string {
	t.Helper()

	wd, err := os.Getwd()
	if err != nil {
		t.Fatalf("getting working directory: %v", err)
	}
	repoRoot := filepath.Dir(wd)

	rel, err := filepath.Rel(repoRoot, absPath)
	if err != nil {
		t.Fatalf("computing relative path for %s: %v", absPath, err)
	}
	return path.Join("github.com/zchee/spanner-manager", filepath.ToSlash(rel))
}

func runGoTestDir(t *testing.T, dir string) {
	t.Helper()

	cmd := exec.CommandContext(t.Context(), "go", "test", ".")
	cmd.Dir = dir
	output, err := cmd.CombinedOutput()
	if err != nil {
		t.Fatalf("go test . in %s failed: %v\n%s", dir, err, output)
	}
}
